        'id': id,
        'email': email,
        'name': name,
        'avatarUrl': avatarUrl,
        'metadata': metadata,
      };

  factory UserModel.fromJson(Map<String, dynamic> json) => UserModel(
        id: json['id'] as String,
        email: json['email'] as String,
        name: json['name'] as String,
