// lib/services/auth_manager.dart
import 'dart:async';
import 'package:flutter/foundation.dart';

enum AuthState {
  initial,
  authenticated,
  unauthenticated,
  loading,
  tokenRefreshing,
  error,
}

class AuthResult {
  final bool success;
  final String? errorMessage;
  final UserModel? user;
  final AuthTokens? tokens;

  AuthResult({
    required this.success,
    this.errorMessage,
    this.user,
    this.tokens,
  });

  factory AuthResult.success({required UserModel user, required AuthTokens tokens}) =>
      AuthResult(success: true, user: user, tokens: tokens);

  factory AuthResult.failure(String message) =>
      AuthResult(success: false, errorMessage: message);
}

class AuthManager extends ChangeNotifier {
  final AuthStorageService _storage;

  AuthState _state = AuthState.initial;
  UserModel? _currentUser;
  AuthTokens? _currentTokens;
  String? _errorMessage;
  Timer? _tokenRefreshTimer;

  // Simulated API delay for demo purposes
  static const Duration _simulatedApiDelay = Duration(seconds: 1);
  // Max session age before requiring re-login (30 days)
  static const Duration _maxSessionAge = Duration(days: 30);

  AuthManager({AuthStorageService? storage})
      : _storage = storage ?? AuthStorageService();

  // Getters
  AuthState get state => _state;
  UserModel? get currentUser => _currentUser;
  AuthTokens? get currentTokens => _currentTokens;
  String? get errorMessage => _errorMessage;
  bool get isAuthenticated => _state == AuthState.authenticated;
  bool get isLoading => _state == AuthState.loading || _state == AuthState.tokenRefreshing;

  /// Initialize auth manager - call on app startup
  Future<void> initialize() async {
    _setState(AuthState.loading);

    try {
      final isLoggedIn = await _storage.isLoggedIn();
      if (!isLoggedIn) {
        _setState(AuthState.unauthenticated);
        return;
      }

      // Check session age
      final lastLogin = await _storage.getLastLoginTime();
      if (lastLogin != null &&
          DateTime.now().difference(lastLogin) > _maxSessionAge) {
        await _performLogout();
        _setError('Session expired. Please log in again.');
        return;
      }

      // Restore tokens
      final tokens = await _storage.getTokens();
      if (tokens == null) {
        await _performLogout();
        _setState(AuthState.unauthenticated);
        return;
      }

      // Check if tokens are expired
      if (tokens.isExpired) {
        // Try to refresh
        final refreshResult = await _refreshTokens(tokens.refreshToken);
        if (!refreshResult) {
          await _performLogout();
          _setError('Session expired. Please log in again.');
          return;
        }
      } else {
        _currentTokens = tokens;
      }

      // Restore user data
      final user = await _storage.getUserData();
      if (user == null) {
        await _performLogout();
        _setState(AuthState.unauthenticated);
        return;
      }

      _currentUser = user;
      _scheduleTokenRefresh();
      _setState(AuthState.authenticated);
    } catch (e) {
      _setError('Failed to restore session: ${e.toString()}');
    }
  }

  /// Login with email and password
  Future<AuthResult> login({
    required String email,
    required String password,
    bool rememberMe = true,
  }) async {
    _setState(AuthState.loading);
    _errorMessage = null;

    try {
      // Simulate API call - replace with actual API integration
      final result = await _simulateLoginApi(email, password);

      if (!result.success) {
        _setError(result.errorMessage ?? 'Login failed');
        return result;
      }

      // Save tokens
      await _storage.saveTokens(result.tokens!);
      _currentTokens = result.tokens;

      // Save user data
      await _storage.saveUserData(result.user!);
      _currentUser = result.user;

      // Save session state
      await _storage.setLoggedIn(true);
      await _storage.setRememberMe(rememberMe);

      // Schedule token refresh
      _scheduleTokenRefresh();

      _setState(AuthState.authenticated);
      return result;
    } catch (e) {
      _setError('Login failed: ${e.toString()}');
      return AuthResult.failure(e.toString());
    }
  }

  /// Register a new user
  Future<AuthResult> register({
    required String email,
    required String password,
    required String name,
  }) async {
    _setState(AuthState.loading);
    _errorMessage = null;

    try {
      // Simulate API call - replace with actual API integration
      final result = await _simulateRegisterApi(email, password, name);

      if (!result.success) {
        _setError(result.errorMessage ?? 'Registration failed');
        return result;
      }

      // Save tokens
      await _storage.saveTokens(result.tokens!);
      _currentTokens = result.tokens;

      // Save user data
      await _storage.saveUserData(result.user!);
      _currentUser = result.user;

      // Save session state
      await _storage.setLoggedIn(true);
      await _storage.setRememberMe(true);

      // Schedule token refresh
      _scheduleTokenRefresh();

      _setState(AuthState.authenticated);
      return result;
    } catch (e) {
      _setError('Registration failed: ${e.toString()}');
      return AuthResult.failure(e.toString());
    }
  }

  /// Logout
  Future<void> logout() async {
    _setState(AuthState.loading);
    try {
      // Simulate API call to invalidate tokens server-side
      await _simulateLogoutApi();
    } catch (_) {
      // Even if server-side logout fails, clear local data
    }
    await _performLogout();
    _setState(AuthState.unauthenticated);
  }

  /// Update user profile
  Future<bool> updateProfile({
    String? name,
    String? avatarUrl,
    Map<String, dynamic>? metadata,
  }) async {
    if (_currentUser == null) return false;

    try {
      final updatedUser = UserModel(
        id: _currentUser!.id,
        email: _currentUser!.email,
        name: name ?? _currentUser!.name,
        avatarUrl: avatarUrl ?? _currentUser!.avatarUrl,
        metadata: metadata ?? _currentUser!.metadata,
      );

      await _storage.saveUserData(updatedUser);
      _currentUser = updatedUser;
      notifyListeners();
      return true;
    } catch (e) {
      return false;
    }
  }

  /// Get a valid access token (refreshing if needed)
  Future<String?> getValidAccessToken() async {
    if (_currentTokens == null) return null;

    if (_currentTokens!.isAboutToExpire) {
      final refreshed = await _refreshTokens(_currentTokens!.refreshToken);
      if (!refreshed) return null;
    }

    return _currentTokens!.accessToken;
  }

  /// Force refresh tokens
  Future<bool> forceRefreshTokens() async {
    if (_currentTokens == null) return false;
    return _refreshTokens(_currentTokens!.refreshToken);
  }

  // Private methods

  Future<bool> _refreshTokens(String refreshToken) async {
    _setState(AuthState.tokenRefreshing);
    try {
      // Simulate token refresh API call
      final newTokens = await _simulateRefreshTokenApi(refreshToken);
      if (newTokens == null) return false;

      await _storage.saveTokens(newTokens);
      _currentTokens = newTokens;
      _scheduleTokenRefresh();

      if (_currentUser != null) {
        _setState(AuthState.authenticated);
      }
      return true;
    } catch (e) {
      return false;
    }
  }

  void _scheduleTokenRefresh() {
    _tokenRefreshTimer?.cancel();

    if (_currentTokens == null) return;

    final timeUntilExpiry =
        _currentTokens!.expiresAt.difference(DateTime.now());
    // Refresh 5 minutes before expiry
    final refreshIn = timeUntilExpiry - const Duration(minutes: 5);

    if (refreshIn.isNegative) {
      // Token is already about to expire or expired, refresh now
      _refreshTokens(_currentTokens!.refreshToken);
      return;
    }

    _tokenRefreshTimer = Timer(refreshIn, () {
      if (_currentTokens != null) {
        _refreshTokens(_currentTokens!.refreshToken);
      }
    });
  }

  Future<void> _performLogout() async {
    _tokenRefreshTimer?.cancel();
    _tokenRefreshTimer = null;
    _currentUser = null;
    _currentTokens = null;
    await _storage.clearAll();
  }

  void _setState(AuthState newState) {
    _state = newState;
    notifyListeners();
  }

  void _setError(String message) {
    _errorMessage = message;
    _state = AuthState.error;
    notifyListeners();
  }

  @override
  void dispose() {
    _tokenRefreshTimer?.cancel();
    super.dispose();
  }

  // ============================================================
  // SIMULATED API CALLS - Replace these with actual HTTP calls
  // ============================================================

  Future<AuthResult> _simulateLoginApi(String email, String password) async {
    await Future.delayed(_simulatedApiDelay);

    // Simulate validation
    if (email.isEmpty || password.isEmpty) {
      return AuthResult.failure('Email and password are required');
    }

    if (password.length < 6) {
      return AuthResult.failure('Invalid credentials');
    }

    // Simulate successful response
    return AuthResult.success(
      user: UserModel(
        id: 'user_${DateTime.now().millisecondsSinceEpoch}',
        email: email,
        name: email.split('@').first,
        metadata: {'loginMethod': 'email'},
      ),
      tokens: AuthTokens(
        accessToken: 'access_${DateTime.now().millisecondsSinceEpoch}',
        refreshToken: 'refresh_${DateTime.now().millisecondsSinceEpoch}',
        expiresAt: DateTime.now().add(const Duration(hours: 1)),
      ),
    );
  }

  Future<AuthResult> _simulateRegisterApi(
      String email, String password, String name) async {
    await Future.delayed(_simulatedApiDelay);

    if (email.isEmpty || password.isEmpty || name.isEmpty) {
      return AuthResult.failure('All fields are required');
    }

    if (password.length < 6) {
      return AuthResult.failure('Password must be at least 6 characters');
    }

    return AuthResult.success(
      user: UserModel(
        id: 'user_${DateTime.now().millisecondsSinceEpoch}',
        email: email,
        name: name,
        metadata: {'loginMethod': 'email', 'isNewUser': true},
      ),
      tokens: AuthTokens(
        accessToken: 'access_${DateTime.now().millisecondsSinceEpoch}',
        refreshToken: 'refresh_${DateTime.now().millisecondsSinceEpoch}',
        expiresAt: DateTime.now().add(const Duration(hours: 1)),
      ),
    );
  }

  Future<AuthTokens?> _simulateRefreshTokenApi(String refreshToken) async {
    await Future.delayed(const Duration(milliseconds: 500));

    return AuthTokens(
      accessToken: 'access_refreshed_${DateTime.now().millisecondsSinceEpoch}',
      refreshToken:
          'refresh_refreshed_${DateTime.now().millisecondsSinceEpoch}',
      expiresAt: DateTime.now().add(const Duration(hours: 1)),
    );
  }

  Future<void> _simulateLogoutApi() async {
    await Future.delayed(const Duration(milliseconds: 300));
  }
}

// lib/main.dart
import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatefulWidget {
  const MyApp({super.key});

  @override
  State<MyApp> createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  late final AuthManager _authManager;
  bool _initialized = false;

  @override
  void initState() {
    super.initState();
    _authManager = AuthManager();
    _initAuth();
  }

  Future<void> _initAuth() async {
    await _authManager.initialize();
    setState(() => _initialized = true);
  }

  @override
  void dispose() {
    _authManager.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Auth Manager Demo',
      theme: ThemeData(
        colorSchemeSeed: Colors.indigo,
        useMaterial3: true,
      ),
      home: _initialized
          ? ListenableBuilder(
              listenable: _authManager,
              builder: (context, _) {
                if (_authManager.isAuthenticated) {
                  return HomeScreen(authManager: _authManager);
                }
                return LoginScreen(authManager: _authManager);
              },
            )
          : const Scaffold(
              body: Center(child: CircularProgressIndicator()),
            ),
    );
  }
}

// Login Screen
class LoginScreen extends StatefulWidget {
  final AuthManager authManager;

  const LoginScreen({super.key, required this.authManager});

  @override
  State<LoginScreen> createState() => _LoginScreenState();
}

class _LoginScreenState extends State<LoginScreen> {
  final _formKey = GlobalKey<FormState>();
  final _emailController = TextEditingController();
  final _passwordController = TextEditingController();
  final _nameController = TextEditingController();
  bool _isRegisterMode = false;
  bool _rememberMe = true;
  bool _obscurePassword = true;

  @override
  void dispose() {
    _emailController.dispose();
    _passwordController.dispose();
    _nameController.dispose();
    super.dispose();
  }

  Future<void> _submit() async {
    if (!_formKey.currentState!.validate()) return;

    AuthResult result;
    if (_isRegisterMode) {
      result = await widget.authManager.register(
        email: _emailController.text.trim(),
        password: _passwordController.text,
        name: _nameController.text.trim(),
      );
    } else {
      result = await widget.authManager.login(
        email: _emailController.text.trim(),
        password: _passwordController.text,
        rememberMe: _rememberMe,
      );
    }

    if (!result.success && mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(result.errorMessage ?? 'An error occurred'),
          backgroundColor: Colors.red,
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    final isLoading = widget.authManager.isLoading;

    return Scaffold(
      body: SafeArea(
        child: Center(
          child: SingleChildScrollView(
            padding: const EdgeInsets.all(24),
            child: ConstrainedBox(
              constraints: const BoxConstraints(maxWidth: 400),
              child: Form(
                key: _formKey,
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    Icon(
                      Icons.lock_outline,
                      size: 80,
                      color: Theme.of(context).colorScheme.primary,
                    ),
                    const SizedBox(height: 16),
                    Text(
                      _isRegisterMode ? 'Create Account' : 'Welcome Back',
                      style: Theme.of(context).textTheme.headlineMedium,
                      textAlign: TextAlign.center,
                    ),
                    const SizedBox(height: 8),
                    Text(
                      _isRegisterMode
                          ? 'Sign up to get started'
                          : 'Sign in to continue',
                      style: Theme.of(context).textTheme.bodyLarge?.copyWith(
                            color: Colors.grey,
                          ),
                      textAlign: TextAlign.center,
                    ),
                    const SizedBox(height: 32),
                    if (_isRegisterMode) ...[
                      TextFormField(
                        controller: _nameController,
                        decoration: const InputDecoration(
                          labelText: 'Full Name',
                          prefixIcon: Icon(Icons.person_outline),
                          border: OutlineInputBorder(),
                        ),
                        textInputAction: TextInputAction.next,
                        validator: (value) {
                          if (_isRegisterMode &&
                              (value == null || value.trim().isEmpty)) {
                            return 'Please enter your name';
                          }
                          return null;
                        },
                      ),
                      const SizedBox(height: 16),
                    ],
                    TextFormField(
                      controller: _emailController,
                      decoration: const InputDecoration(
                        labelText: 'Email',
                        prefixIcon: Icon(Icons.email_outlined),
                        border: OutlineInputBorder(),
                      ),
                      keyboardType: TextInputType.emailAddress,
                      textInputAction: TextInputAction.next,
                      validator: (value) {
                        if (value == null || value.trim().isEmpty) {
                          return 'Please enter your email';
                        }
                        if (!value.contains('@')) {
                          return 'Please enter a valid email';
                        }
                        return null;
                      },
                    ),
                    const SizedBox(height: 16),
                    TextFormField(
                      controller: _passwordController,
                      decoration: InputDecoration(
                        labelText: 'Password',
                        prefixIcon: const Icon(Icons.lock_outline),
                        border: const OutlineInputBorder(),
                        suffixIcon: IconButton(
                          icon: Icon(
                            _obscurePassword
                                ? Icons.visibility_off
                                : Icons.visibility,
                          ),
                          onPressed: () {
                            setState(
                                () => _obscurePassword = !_obscurePassword);
                          },
                        ),
                      ),
                      obscureText: _obscurePassword,
                      textInputAction: TextInputAction.done,
                      onFieldSubmitted: (_) => _submit(),
                      validator: (value) {
                        if (value == null || value.isEmpty) {
                          return 'Please enter your password';
                        }
                        if (value.length < 6) {
                          return 'Password must be at least 6 characters';
                        }
                        return null;
                      },
                    ),
                    if (!_isRegisterMode) ...[
                      const SizedBox(height: 8),
                      Row(
                        children: [
                          Checkbox(
                            value: _rememberMe,
                            onChanged: (value) {
                              setState(() => _rememberMe = value ?? true);
                            },
                          ),
                          const Text('Remember me'),
                        ],
                      ),
                    ],
                    const SizedBox(height: 24),
                    FilledButton(
                      onPressed: isLoading ? null : _submit,
                      style: FilledButton.styleFrom(
                        padding: const EdgeInsets.symmetric(vertical: 16),
                      ),
                      child: isLoading
                          ? const SizedBox(
                              height: 20,
                              width: 20,
                              child: CircularProgressIndicator(
                                strokeWidth: 2,
                                color: Colors.white,
                              ),
                            )
                          : Text(
                              _isRegisterMode ? 'Create Account' : 'Sign In'),
                    ),
                    const SizedBox(height: 16),
                    TextButton(
                      onPressed: isLoading
                          ? null
                          : () {
                              setState(
                                  () => _isRegisterMode = !_isRegisterMode);
                            },
                      child: Text(
                        _isRegisterMode
                            ? 'Already have an account? Sign In'
                            : "Don't have an account? Sign Up",
                      ),
                    ),
                  ],
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }
}

// Home Screen (authenticated)
class HomeScreen extends StatelessWidget {
  final AuthManager authManager;

  const HomeScreen({super.key, required this.authManager});

  @override
  Widget build(BuildContext context) {
    final user = authManager.currentUser;
    final tokens = authManager.currentTokens;

    return Scaffold(
      appBar: AppBar(
        title: const Text('Home'),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh),
            tooltip: 'Refresh Token',
            onPressed: () async {
              final success = await authManager.forceRefreshTokens();
              if (context.mounted) {
                ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(
                    content: Text(success
                        ? 'Token refreshed successfully'
                        : 'Failed to refresh token'),
                  ),
                );
              }
            },
          ),
          IconButton(
            icon: const Icon(Icons.logout),
            tooltip: 'Logout',
            onPressed: () => _showLogoutDialog(context),
          ),
        ],
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(24),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            // User Card
            Card(
              child: Padding(
                padding: const EdgeInsets.all(20),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(
                      children: [
                        CircleAvatar(
                          radius: 30,
                          child: Text(
                            user?.name.isNotEmpty == true
                                ? user!.name[0].toUpperCase()
                                : '?',
                            style: const TextStyle(fontSize: 24),
                          ),
                        ),
                        const SizedBox(width: 16),
                        Expanded(
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(
                                user?.name ?? 'Unknown',
                                style: Theme.of(context)
                                    .textTheme
                                    .titleLarge,
                              ),
                              Text(
                                user?.email ?? 'No email',
                                style: Theme.of(context)
                                    .textTheme
                                    .bodyMedium
                                    ?.copyWith(color: Colors.grey),
                              ),
                            ],
                          ),
                        ),
                      ],
                    ),
                    const Divider(height: 32),
                    _buildInfoRow(context, 'User ID', user?.id ?? 'N/A'),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 16),

            // Session Info Card
            Card(
              child: Padding(
                padding: const EdgeInsets.all(20),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'Session Info',
                      style: Theme.of(context).textTheme.titleMedium,
                    ),
                    const SizedBox(height: 12),
                    _buildInfoRow(
                      context,
                      'Auth State',
                      authManager.state.name,
                    ),
                    const SizedBox(height: 8),
                    _buildInfoRow(
                      context,
                      'Token Expires',
                      tokens?.expiresAt.toLocal().toString() ?? 'N/A',
                    ),
                    const SizedBox(height: 8),
                    _buildInfoRow(
                      context,
                      'Token Expired',
                      tokens?.isExpired.toString() ?? 'N/A',
                    ),
                    const SizedBox(height: 8),
                    _buildInfoRow(
                      context,
                      'Access Token',
                      _truncateToken(tokens?.accessToken),
                    ),
                    const SizedBox(height: 8),
                    _buildInfoRow(
                      context,
                      'Refresh Token',
                      _truncateToken(tokens?.refreshToken),
                    ),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 16),

            // Actions Card
            Card(
              child: Padding(
                padding: const EdgeInsets.all(20),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    Text(
                      'Actions',
                      style: Theme.of(context).textTheme.titleMedium,
                    ),
                    const SizedBox(height: 12),
                    OutlinedButton.icon(
                      onPressed: () => _showUpdateProfileDialog(context),
                      icon: const Icon(Icons.edit),
                      label: const Text('Update Profile'),
                    ),
                    const SizedBox(height: 8),
                    OutlinedButton.icon(
                      onPressed: () async {
                        final token =
                            await authManager.getValidAccessToken();
                        if (context.mounted) {
                          ScaffoldMessenger.of(context).showSnackBar(
                            SnackBar(
                              content: Text(token != null
                                  ? 'Valid token: ${_truncateToken(token)}'
                                  : 'No valid token available'),
                            ),
                          );
                        }
                      },
                      icon: const Icon(Icons.vpn_key),
                      label: const Text('Get Valid Token'),
                    ),
                    const SizedBox(height: 8),
                    FilledButton.icon(
                      onPressed: () => _showLogoutDialog(context),
                      icon: const Icon(Icons.logout),
                      label: const Text('Logout'),
                      style: FilledButton.styleFrom(
                        backgroundColor: Colors.red,
                      ),
                    ),
                  ],
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildInfoRow(BuildContext context, String label, String value) {
    return Row(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        SizedBox(
          width: 120,
          child: Text(
            label,
            style: const TextStyle(
              fontWeight: FontWeight.w600,
              color: Colors.grey,
            ),
          ),
        ),
        Expanded(
          child: Text(
            value,
            style: const TextStyle(fontFamily: 'monospace'),
          ),
        ),
      ],
    );
  }

  String _truncateToken(String? token) {
    if (token == null) return 'N/A';
    if (token.length <= 20) return token;
    return '${token.substring(0, 20)}...';
  }

  void _showLogoutDialog(BuildContext context) {
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        title: const Text('Logout'),
        content: const Text('Are you sure you want to logout?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(),
            child: const Text('Cancel'),
          ),
          FilledButton(
            onPressed: () {
              Navigator.of(ctx).pop();
              authManager.logout();
            },
            style: FilledButton.styleFrom(backgroundColor: Colors.red),
            child: const Text('Logout'),
          ),
        ],
      ),
    );
  }

  void _showUpdateProfileDialog(BuildContext context) {
    final nameController =
        TextEditingController(text: authManager.currentUser?.name ?? '');

    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        title: const Text('Update Profile'),
        content: TextField(
          controller: nameController,
          decoration: const InputDecoration(
            labelText: 'Name',
            border: OutlineInputBorder(),
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(),
            child: const Text('Cancel'),
          ),
          FilledButton(
            onPressed: () async {
              final success = await authManager.updateProfile(
                name: nameController.text.trim(),
              );
              if (ctx.mounted) {
                Navigator.of(ctx).pop();
              }
              if (context.mounted) {
                ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(
                    content: Text(success
                        ? 'Profile updated!'
                        : 'Failed to update profile'),
                  ),
                );
              }
            },
            child: const Text('Save'),
          ),
        ],
      ),
    );
  }
}